const ICAS_MATHS=[{"id":"im20001","state":"AU","section":"icas_maths","grade":2,"topic":"Addition","difficulty":"easy","style":"icas","q":"A bag holds 6 red marbles and 4 blue marbles. How many marbles are in the bag altogether?","options":["8","9","10","11"],"answer":2,"exp":"6+4=10 marbles altogether."},{"id":"im20002","state":"AU","section":"icas_maths","grade":2,"topic":"Subtraction","difficulty":"easy","style":"icas","q":"Jack has 15 stickers. He gives 7 to his friend. How many does he have left?","options":["6","7","8","9"],"answer":2,"exp":"15-7=8 stickers."},{"id":"im20003","state":"AU","section":"icas_maths","grade":2,"topic":"Geometry","difficulty":"easy","style":"icas","q":"Which shape has exactly 4 equal sides and 4 right angles?","options":["Rectangle","Triangle","Square","Circle"],"answer":2,"exp":"A square has 4 equal sides and 4 right angles. A rectangle has 4 right angles but sides may not all be equal."},{"id":"im20004","state":"AU","section":"icas_maths","grade":2,"topic":"Patterns","difficulty":"easy","style":"icas","q":"The pattern is: 5, 10, 15, 20, ___. What is the missing number?","options":["22","23","24","25"],"answer":3,"exp":"Counting by 5s: 5,10,15,20,25."},{"id":"im20005","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"What is 3 groups of 4?","options":["10","11","12","13"],"answer":2,"exp":"3×4=12."},{"id":"im20006","state":"AU","section":"icas_maths","grade":2,"topic":"Time","difficulty":"easy","style":"icas","q":"A clock shows 3:30. Which of these shows the same time?","options":["Half past 2","Half past 3","Quarter past 3","Quarter to 4"],"answer":1,"exp":"3:30 = half past 3."},{"id":"im20007","state":"AU","section":"icas_maths","grade":2,"topic":"Money","difficulty":"easy","style":"icas","q":"Sara has 20 cents. She buys a pencil for 15 cents. How much change does she get?","options":["3c","4c","5c","6c"],"answer":2,"exp":"20-15=5 cents change."},{"id":"im20008","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"Which number is between 45 and 50?","options":["43","44","47","52"],"answer":2,"exp":"47 is between 45 and 50."},{"id":"im20009","state":"AU","section":"icas_maths","grade":2,"topic":"Fractions","difficulty":"easy","style":"icas","q":"What fraction of this shape is shaded if 2 out of 4 equal parts are shaded?","options":["1/4","1/3","1/2","2/3"],"answer":2,"exp":"2 out of 4 = 2/4 = 1/2."},{"id":"im20010","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"A table has 4 legs. How many legs do 7 tables have?","options":["21","24","28","32"],"answer":2,"exp":"7×4=28 legs."},{"id":"im20011","state":"AU","section":"icas_maths","grade":2,"topic":"Addition","difficulty":"easy","style":"icas","q":"What is 65 + 28?","options":["83","93","103","73"],"answer":1,"exp":"65+28: 65+20=85, 85+8=93."},{"id":"im20012","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"Anna has 3 bags of 8 apples. How many apples does she have in total?","options":["20","22","24","26"],"answer":2,"exp":"3×8=24 apples."},{"id":"im20013","state":"AU","section":"icas_maths","grade":2,"topic":"Patterns","difficulty":"medium","style":"icas","q":"What is the next number in the pattern? 2, 4, 8, 16, ___","options":["18","20","24","32"],"answer":3,"exp":"Each number doubles: 16×2=32."},{"id":"im20014","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"A box holds 10 crayons. There are 6 boxes. How many crayons in total?","options":["50","55","60","65"],"answer":2,"exp":"6×10=60 crayons."},{"id":"im20015","state":"AU","section":"icas_maths","grade":2,"topic":"Subtraction","difficulty":"easy","style":"icas","q":"What is 80 - 37?","options":["33","43","47","53"],"answer":1,"exp":"80-37: 80-40=40, 40+3=43."},{"id":"im20016","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"Which of these numbers is an odd number?","options":["14","22","37","44"],"answer":2,"exp":"Odd numbers end in 1,3,5,7,9. 37 ends in 7 — odd."},{"id":"im20017","state":"AU","section":"icas_maths","grade":2,"topic":"Division","difficulty":"easy","style":"icas","q":"Kim has 24 lollies. She shares them equally among 4 friends. How many does each friend get?","options":["4","5","6","7"],"answer":2,"exp":"24÷4=6."},{"id":"im20018","state":"AU","section":"icas_maths","grade":2,"topic":"Time","difficulty":"easy","style":"icas","q":"What time is 2 hours after 9 o'clock?","options":["10 o'clock","11 o'clock","12 o'clock","1 o'clock"],"answer":1,"exp":"9+2=11 o'clock."},{"id":"im20019","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"Which is the largest number? 308, 380, 830, 083","options":["308","380","830","083"],"answer":2,"exp":"Compare: 830>380>308>83. Largest is 830."},{"id":"im20020","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"There are 5 rows of seats with 6 seats in each row. How many seats altogether?","options":["25","28","30","32"],"answer":2,"exp":"5×6=30 seats."},{"id":"im30001","state":"AU","section":"icas_maths","grade":3,"topic":"Addition","difficulty":"easy","style":"icas","q":"What is 347 + 258?","options":["595","605","615","625"],"answer":1,"exp":"347+258: 300+200=500, 47+58=105. 500+105=605."},{"id":"im30002","state":"AU","section":"icas_maths","grade":3,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"A bag of fruit weighs 2.5 kg. What is the total weight of 4 bags?","options":["8 kg","9 kg","10 kg","12 kg"],"answer":2,"exp":"4×2.5=10 kg."},{"id":"im30003","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"easy","style":"icas","q":"Which fraction is equivalent to 2/4?","options":["1/2","1/3","2/6","3/8"],"answer":0,"exp":"2/4 = 1/2 (divide numerator and denominator by 2)."},{"id":"im30004","state":"AU","section":"icas_maths","grade":3,"topic":"Division","difficulty":"easy","style":"icas","q":"A shop has 144 eggs packed in trays of 12. How many trays are there?","options":["10","11","12","13"],"answer":2,"exp":"144÷12=12 trays."},{"id":"im30005","state":"AU","section":"icas_maths","grade":3,"topic":"Geometry","difficulty":"easy","style":"icas","q":"What is the perimeter of a square with sides of 9 cm?","options":["27 cm","36 cm","45 cm","81 cm"],"answer":1,"exp":"Perimeter = 4×9=36 cm."},{"id":"im30006","state":"AU","section":"icas_maths","grade":3,"topic":"Statistics","difficulty":"medium","style":"icas","q":"Tom collects 24 cards on Monday, 18 on Tuesday, and 12 on Wednesday. What is the mean number of cards collected per day?","options":["16","17","18","19"],"answer":2,"exp":"Mean = (24+18+12)÷3 = 54÷3 = 18."},{"id":"im30007","state":"AU","section":"icas_maths","grade":3,"topic":"Number Theory","difficulty":"easy","style":"icas","q":"Which of these is NOT a multiple of 6?","options":["24","30","34","36"],"answer":2,"exp":"34÷6=5 remainder 4. 34 is not a multiple of 6."},{"id":"im30008","state":"AU","section":"icas_maths","grade":3,"topic":"Time","difficulty":"medium","style":"icas","q":"A movie starts at 2:15 pm and runs for 1 hour 40 minutes. When does it end?","options":["3:45 pm","3:50 pm","3:55 pm","4:00 pm"],"answer":2,"exp":"2:15 + 1:40 = 3:55 pm."},{"id":"im30009","state":"AU","section":"icas_maths","grade":3,"topic":"Geometry","difficulty":"easy","style":"icas","q":"What is the area of a rectangle that is 8 m long and 5 m wide?","options":["26 m²","30 m²","40 m²","45 m²"],"answer":2,"exp":"Area = 8×5=40 m²."},{"id":"im30010","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"medium","style":"icas","q":"In a class of 30 students, 2/5 are wearing glasses. How many students wear glasses?","options":["10","12","14","15"],"answer":1,"exp":"2/5×30=12 students."},{"id":"im30011","state":"AU","section":"icas_maths","grade":3,"topic":"Subtraction","difficulty":"easy","style":"icas","q":"What is 600 - 247?","options":["343","353","363","373"],"answer":1,"exp":"600-247: 600-200=400, 400-47=353."},{"id":"im30012","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":"medium","style":"icas","q":"The temperature was -3°C in the morning. By noon it had risen by 8°C. What was the noon temperature?","options":["4°C","5°C","6°C","7°C"],"answer":1,"exp":"−3+8=5°C."},{"id":"im30013","state":"AU","section":"icas_maths","grade":3,"topic":"Division","difficulty":"easy","style":"icas","q":"4,500 ÷ 9 = ?","options":["400","450","500","550"],"answer":2,"exp":"4500÷9=500."},{"id":"im30014","state":"AU","section":"icas_maths","grade":3,"topic":"Geometry","difficulty":"medium","style":"icas","q":"A right-angled triangle has legs of 3 cm and 4 cm. What is its hypotenuse?","options":["5 cm","6 cm","7 cm","8 cm"],"answer":0,"exp":"3-4-5 is a Pythagorean triple: √(9+16)=√25=5 cm."},{"id":"im30015","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":"easy","style":"icas","q":"Which number has the digit 7 in the hundreds place?","options":["7,840","8,720","9,073","1,709"],"answer":1,"exp":"8,720: 8=thousands, 7=hundreds, 2=tens, 0=ones."},{"id":"im30016","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"medium","style":"icas","q":"What is 3/4 + 1/8?","options":["4/12","5/8","7/8","1"],"answer":2,"exp":"3/4=6/8. 6/8+1/8=7/8."},{"id":"im30017","state":"AU","section":"icas_maths","grade":3,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"A factory makes 250 items each hour. How many items in an 8-hour shift?","options":["1,800","2,000","2,200","2,500"],"answer":1,"exp":"8×250=2,000."},{"id":"im30018","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":"medium","style":"icas","q":"What is 7² − 4²?","options":["25","30","33","37"],"answer":2,"exp":"49-16=33."},{"id":"im30019","state":"AU","section":"icas_maths","grade":3,"topic":"Division","difficulty":"easy","style":"icas","q":"Find the missing number: __ × 7 = 91","options":["12","13","14","15"],"answer":1,"exp":"91÷7=13. Check: 13×7=91 ✓."},{"id":"im30020","state":"AU","section":"icas_maths","grade":3,"topic":"Decimals","difficulty":"medium","style":"icas","q":"Mia ran 2.35 km in the morning and 1.75 km in the afternoon. What was the total distance?","options":["3.90 km","4.00 km","4.10 km","4.20 km"],"answer":2,"exp":"2.35+1.75=4.10 km."},{"id":"im40001","state":"AU","section":"icas_maths","grade":4,"topic":"Multiplication","difficulty":"medium","style":"icas","q":"A school trip costs $45 per student. There are 28 students. What is the total cost?","options":["$1,160","$1,240","$1,260","$1,280"],"answer":2,"exp":"28×45=28×40+28×5=1120+140=$1,260."},{"id":"im40002","state":"AU","section":"icas_maths","grade":4,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"Which of the following is a prime number?","options":["51","57","59","63"],"answer":2,"exp":"59 is prime. 51=3×17, 57=3×19, 63=7×9."},{"id":"im40003","state":"AU","section":"icas_maths","grade":4,"topic":"Measurement","difficulty":"medium","style":"icas","q":"A jug holds 2.4 litres when full. 600 mL is poured out. How much remains?","options":["1.6 L","1.7 L","1.8 L","2.0 L"],"answer":2,"exp":"2400mL - 600mL = 1800mL = 1.8 L."},{"id":"im40004","state":"AU","section":"icas_maths","grade":4,"topic":"Percentage","difficulty":"medium","style":"icas","q":"What is 15% of 80?","options":["10","12","14","15"],"answer":1,"exp":"15% of 80 = 0.15×80=12."},{"id":"im40005","state":"AU","section":"icas_maths","grade":4,"topic":"Ratio","difficulty":"medium","style":"icas","q":"The ratio of cats to dogs in a shelter is 3:5. There are 24 cats. How many dogs?","options":["30","35","40","45"],"answer":2,"exp":"Each part = 24÷3=8. Dogs = 5×8=40."},{"id":"im40006","state":"AU","section":"icas_maths","grade":4,"topic":"Number","difficulty":"medium","style":"icas","q":"What is the value of 4³ + 2⁴?","options":["72","80","84","96"],"answer":1,"exp":"4³=64. 2⁴=16. 64+16=80."},{"id":"im40007","state":"AU","section":"icas_maths","grade":4,"topic":"Geometry","difficulty":"easy","style":"icas","q":"A rectangle has area 84 cm² and length 12 cm. What is its width?","options":["5 cm","6 cm","7 cm","8 cm"],"answer":2,"exp":"Width = 84÷12=7 cm."},{"id":"im40008","state":"AU","section":"icas_maths","grade":4,"topic":"Fractions","difficulty":"hard","style":"icas","q":"Which of these is the correct order from smallest to largest?\n0.35, 3/8, 0.4, 5/12","options":["0.35, 3/8, 5/12, 0.4","0.35, 3/8, 0.4, 5/12","3/8, 0.35, 5/12, 0.4","5/12, 0.4, 3/8, 0.35"],"answer":1,"exp":"0.35=0.350, 3/8=0.375, 0.4=0.400, 5/12=0.417. Ascending: 0.35, 3/8, 0.4, 5/12 — option B."},{"id":"im40009","state":"AU","section":"icas_maths","grade":4,"topic":"Rates","difficulty":"hard","style":"icas","q":"If 5 taps fill a pool in 24 hours, how long will 8 taps take?","options":["12h","14h","15h","16h"],"answer":2,"exp":"5×24=120 tap-hours. 8 taps: 120÷8=15 hours."},{"id":"im40010","state":"AU","section":"icas_maths","grade":4,"topic":"Number Theory","difficulty":"hard","style":"icas","q":"A number is divisible by 4 and by 9. What is the smallest such number greater than 100?","options":["108","112","116","120"],"answer":0,"exp":"Must be divisible by LCM(4,9)=36. Multiples of 36: 36,72,108. 108>100, divisible by 36 ✓."},{"id":"im40011","state":"AU","section":"icas_maths","grade":4,"topic":"Fractions","difficulty":"medium","style":"icas","q":"3/4 of a number is 45. What is the number?","options":["55","60","65","70"],"answer":1,"exp":"Number = 45×4/3=60."},{"id":"im40012","state":"AU","section":"icas_maths","grade":4,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"What is the sum of all prime numbers between 20 and 30?","options":["52","54","56","58"],"answer":0,"exp":"Primes: 23,29. Sum=52."},{"id":"im40013","state":"AU","section":"icas_maths","grade":4,"topic":"Speed","difficulty":"medium","style":"icas","q":"A train travels 420 km in 3.5 hours. What is its average speed?","options":["100 km/h","110 km/h","120 km/h","130 km/h"],"answer":2,"exp":"Speed=420÷3.5=120 km/h."},{"id":"im40014","state":"AU","section":"icas_maths","grade":4,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"What is the LCM of 12 and 18?","options":["24","30","36","72"],"answer":2,"exp":"12=2²×3, 18=2×3². LCM=2²×3²=36."},{"id":"im40015","state":"AU","section":"icas_maths","grade":4,"topic":"Percentage","difficulty":"medium","style":"icas","q":"A price drops from $80 to $60. What is the percentage decrease?","options":["20%","25%","30%","33%"],"answer":1,"exp":"Decrease=$20. %=(20/80)×100=25%."},{"id":"im40016","state":"AU","section":"icas_maths","grade":4,"topic":"Ratio","difficulty":"medium","style":"icas","q":"In a bag of 24 marbles, the ratio of red to blue to green is 1:2:3. How many green marbles are there?","options":["4","6","8","12"],"answer":3,"exp":"Total parts=6. Each part=24÷6=4. Green=3×4=12."},{"id":"im40017","state":"AU","section":"icas_maths","grade":4,"topic":"Patterns","difficulty":"easy","style":"icas","q":"What is the next term in the sequence: 1, 4, 9, 16, 25, ___?","options":["30","36","40","49"],"answer":1,"exp":"Square numbers: 6²=36."},{"id":"im40018","state":"AU","section":"icas_maths","grade":4,"topic":"Algebra","difficulty":"medium","style":"icas","q":"Solve: 3x + 7 = 28","options":["5","6","7","8"],"answer":2,"exp":"3x=21 → x=7."},{"id":"im40019","state":"AU","section":"icas_maths","grade":4,"topic":"Geometry","difficulty":"medium","style":"icas","q":"A cube has a volume of 125 cm³. What is the length of one edge?","options":["4 cm","5 cm","6 cm","7 cm"],"answer":1,"exp":"∛125=5 cm."},{"id":"im40020","state":"AU","section":"icas_maths","grade":4,"topic":"Decimals","difficulty":"medium","style":"icas","q":"What is 2.4 × 1.5?","options":["2.6","3.2","3.6","4.2"],"answer":2,"exp":"2.4×1.5=2.4+1.2=3.6."},{"id":"im50001","state":"AU","section":"icas_maths","grade":5,"topic":"Rates","difficulty":"hard","style":"icas","q":"A car's fuel tank holds 60 litres. The car uses 9.5 litres per 100 km. How far can it travel on a full tank?","options":["About 548 km","About 600 km","About 632 km","About 658 km"],"answer":2,"exp":"60÷9.5×100=6316.../100? 60÷9.5=6.315 × 100=631.6≈632 km."},{"id":"im50002","state":"AU","section":"icas_maths","grade":5,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"What is the HCF of 36 and 54?","options":["6","9","12","18"],"answer":3,"exp":"36=2²×3², 54=2×3³. HCF=2×3²=18."},{"id":"im50003","state":"AU","section":"icas_maths","grade":5,"topic":"Trigonometry","difficulty":"hard","style":"icas","q":"If sin(x)=0.6, what is cos(x)? (Pythagorean identity)","options":["0.4","0.6","0.8","1.0"],"answer":2,"exp":"sin²x+cos²x=1. cos²x=1-0.36=0.64. cosx=0.8."},{"id":"im50004","state":"AU","section":"icas_maths","grade":5,"topic":"Percentage","difficulty":"hard","style":"icas","q":"A 20% discount is applied to a price, and then 10% GST is added. What is the net change from the original?","options":["12% decrease","10% decrease","8% decrease","12% increase"],"answer":2,"exp":"0.80×1.10=0.88. Net: 12% decrease."},{"id":"im50005","state":"AU","section":"icas_maths","grade":3,"topic":"Statistics","difficulty":5,"style":"icas","q":"The average of 6 numbers is 14. If one number is removed, the average becomes 15. What was the removed number?","options":["6","7","8","9"],"answer":3,"exp":"Sum of 6 = 84. Sum of 5 = 75. Removed = 84-75=9. Hmm: removed=9, answer D."},{"id":"im50006","state":"AU","section":"icas_maths","grade":5,"topic":"Fractions","difficulty":"hard","style":"icas","q":"What is 3/8 ÷ 9/16?","options":["1/6","2/3","3/4","6/7"],"answer":1,"exp":"3/8 × 16/9 = 48/72 = 2/3."},{"id":"im50007","state":"AU","section":"icas_maths","grade":5,"topic":"Statistics","difficulty":"medium","style":"icas","q":"In a class test, the scores of 5 students are 72, 85, 91, 68, 79. What is the median score?","options":["79","80","81","82"],"answer":0,"exp":"Sort: 68,72,79,85,91. Median = 79."},{"id":"im50008","state":"AU","section":"icas_maths","grade":1,"topic":"Geometry","difficulty":5,"style":"icas","q":"A sphere has radius 6 cm. What is its volume? (Use π = 3.14)","options":["452.2 cm³","904.3 cm³","678.2 cm³","301.4 cm³"],"answer":1,"exp":"V=(4/3)πr³=(4/3)×3.14×216=3.14×288=904.32÷2? Wait: (4/3)×3.14×6³=(4/3)×3.14×216=4×3.14×72=4×226.08=904.3. Hmm: 904.3 is option B."},{"id":"im50009","state":"AU","section":"icas_maths","grade":5,"topic":"Number","difficulty":"medium","style":"icas","q":"What is (2.5)² + (1.5)²?","options":["6.5","7.5","8.5","9.5"],"answer":2,"exp":"6.25+2.25=8.5."},{"id":"im50010","state":"AU","section":"icas_maths","grade":5,"topic":"Patterns","difficulty":"hard","style":"icas","q":"A sequence has T_n = 3n² - 2. What is T_5?","options":["70","72","73","75"],"answer":2,"exp":"T_5=3(25)-2=75-2=73."},{"id":"im50011","state":"AU","section":"icas_maths","grade":5,"topic":"Probability","difficulty":"hard","style":"icas","q":"The probability of drawing a red card from a standard deck is 1/2. If 3 cards are drawn (with replacement), what is P(all red)?","options":["1/4","1/8","1/6","3/8"],"answer":1,"exp":"(1/2)³=1/8."},{"id":"im50012","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"medium","style":"icas","q":"Simplify: 2x + 3y - x + 5y","options":["3x+8y","x+8y","x+2y","3x+2y"],"answer":1,"exp":"(2x-x)+(3y+5y)=x+8y."},{"id":"im50013","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"hard","style":"icas","q":"What is the surface area of a rectangular box 5×4×3 cm?","options":["74 cm²","80 cm²","94 cm²","120 cm²"],"answer":2,"exp":"SA=2(5×4+5×3+4×3)=2(20+15+12)=2×47=94 cm²."},{"id":"im50014","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"medium","style":"icas","q":"If f(x) = x² - 2x + 1, what is f(4)?","options":["7","8","9","10"],"answer":2,"exp":"f(4)=16-8+1=9."},{"id":"im50015","state":"AU","section":"icas_maths","grade":5,"topic":"Rates","difficulty":"hard","style":"icas","q":"A boat travels 120 km downstream in 3 hours and 120 km upstream in 4 hours. What is the speed of the current?","options":["4 km/h","5 km/h","6 km/h","7 km/h"],"answer":1,"exp":"Downstream: 40 km/h. Upstream: 30 km/h. Current=(40-30)/2=5 km/h."},{"id":"im50016","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"hard","style":"icas","q":"A quadratic equation has roots 4 and -3. What is the equation?","options":["x²-x-12=0","x²+x-12=0","x²-x+12=0","x²+x+12=0"],"answer":0,"exp":"Sum=1, product=-12. x²-(sum)x+product=x²-x-12=0."},{"id":"im50017","state":"AU","section":"icas_maths","grade":5,"topic":"Number","difficulty":"hard","style":"icas","q":"What is the value of ∑(k=1 to 5) k³?","options":["225","196","169","256"],"answer":0,"exp":"1³+2³+3³+4³+5³=1+8+27+64+125=225. Note: (n(n+1)/2)²=(15/2)²=(7.5)²=56.25. Actually sum of cubes = (n(n+1)/2)²=(5×6/2)²=15²=225."},{"id":"im50018","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"hard","style":"icas","q":"An angle in a regular polygon is 150°. How many sides does the polygon have?","options":["10","11","12","15"],"answer":2,"exp":"Interior angle=(n-2)×180/n=150 → 180n-360=150n → 30n=360 → n=12."},{"id":"im50019","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"medium","style":"icas","q":"What is the area of a circle inscribed in a square of side 10 cm? (Use π=3.14)","options":["78.5 cm²","80.0 cm²","25π cm²","50π cm²"],"answer":0,"exp":"Circle radius = half the side = 5 cm. Area=π×25=3.14×25=78.5 cm²."},{"id":"im50020","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Two numbers have sum 50 and product 576. What are they?","options":["18 and 32","20 and 30","24 and 26","22 and 28"],"answer":0,"exp":"n(50-n)=576. n²-50n+576=0. (n-18)(n-32)=0. n=18 or 32."},{"id":"im60001","state":"AU","section":"icas_maths","grade":0,"topic":"Number Theory","difficulty":6,"style":"icas","q":"A number when divided by 8 gives remainder 5 and when divided by 6 gives remainder 3. What is the smallest such positive number?","options":["21","29","37","45"],"answer":0,"exp":"Numbers ≡5(mod 8): 5,13,21,29,37... Check mod 6: 29÷6=4r5 ✗, 13÷6=2r1 ✗, 21÷6=3r3 ✓. Answer: 21? 21÷8=2r5 ✓, 21÷6=3r3 ✓. Yes, 21."},{"id":"im60002","state":"AU","section":"icas_maths","grade":6,"topic":"Number","difficulty":"hard","style":"icas","q":"The sum of the first n natural numbers is n(n+1)/2. What is the sum of the first 50 even numbers?","options":["2500","2550","2600","2650"],"answer":1,"exp":"First 50 even: 2+4+...+100=2(1+2+...+50)=2×(50×51/2)=50×51=2550."},{"id":"im60003","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"If log₂(x) = 5, what is x?","options":["10","16","25","32"],"answer":3,"exp":"log₂(x)=5 means 2⁵=x=32."},{"id":"im60004","state":"AU","section":"icas_maths","grade":6,"topic":"Geometry","difficulty":"hard","style":"icas","q":"A 12 m ladder leans against a wall. The foot is 5 m from the base of the wall. How high up the wall does the ladder reach?","options":["√119 m","√143 m","√144 m","√169 m"],"answer":0,"exp":"h=√(12²-5²)=√(144-25)=√119 m."},{"id":"im60005","state":"AU","section":"icas_maths","grade":6,"topic":"Probability","difficulty":"hard","style":"icas","q":"P(A) = 0.4, P(B|A) = 0.5. What is P(A and B)?","options":["0.1","0.2","0.3","0.4"],"answer":1,"exp":"P(A∩B)=P(A)×P(B|A)=0.4×0.5=0.2."},{"id":"im60006","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"The quadratic y=ax²+bx+c has vertex at (2,-3) and passes through (0,5). What is the value of a?","options":["1","2","3","4"],"answer":1,"exp":"Vertex form: y=a(x-2)²-3. At x=0: 5=a(4)-3 → 4a=8 → a=2."},{"id":"im60007","state":"AU","section":"icas_maths","grade":6,"topic":"Combinatorics","difficulty":"medium","style":"icas","q":"How many ways can 4 different books be arranged on a shelf?","options":["12","16","24","48"],"answer":2,"exp":"4!=4×3×2×1=24 ways."},{"id":"im60008","state":"AU","section":"icas_maths","grade":6,"topic":"Number","difficulty":"hard","style":"icas","q":"A geometric series has first term 3 and ratio 2. What is the sum of the first 8 terms?","options":["762","765","768","771"],"answer":1,"exp":"S=3(2⁸-1)/(2-1)=3×255=765."},{"id":"im60009","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Solve: |2x - 3| = 7","options":["x=5 or x=-2","x=5 or x=2","x=-5 or x=2","x=5 or x=-5"],"answer":0,"exp":"2x-3=7 → x=5. 2x-3=-7 → x=-2. Solutions: x=5 or x=-2."},{"id":"im60010","state":"AU","section":"icas_maths","grade":6,"topic":"Geometry","difficulty":"medium","style":"icas","q":"A triangle has vertices (0,0), (6,0), (3,4). What is its area?","options":["10","12","14","16"],"answer":1,"exp":"Base=6, height=4. Area=½×6×4=12 sq units."},{"id":"im60011","state":"AU","section":"icas_maths","grade":6,"topic":"Number Theory","difficulty":"hard","style":"icas","q":"What is the remainder when 3^100 is divided by 4?","options":["0","1","2","3"],"answer":1,"exp":"3¹≡3,3²≡1,3³≡3,3⁴≡1(mod 4). Cycle 2. 100 even → 3^100≡1(mod 4)."},{"id":"im60012","state":"AU","section":"icas_maths","grade":6,"topic":"Statistics","difficulty":"hard","style":"icas","q":"The mean of 10 numbers is 25. Six of them have a mean of 20. What is the mean of the other four?","options":["30","32.5","35","37.5"],"answer":1,"exp":"Total=250. Sum of 6=120. Sum of 4=130. Mean=130÷4=32.5."},{"id":"im60013","state":"AU","section":"icas_maths","grade":6,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"What is the value of C(8,3)?","options":["28","56","70","84"],"answer":1,"exp":"C(8,3)=8!/(3!5!)=(8×7×6)/6=336/6=56."},{"id":"im60014","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"A parabola y=x²-4x+3 intersects the x-axis at two points. What is the distance between them?","options":["1","2","3","4"],"answer":1,"exp":"Roots: x²-4x+3=0 → (x-1)(x-3)=0 → x=1,3. Distance=3-1=2."},{"id":"im60015","state":"AU","section":"icas_maths","grade":6,"topic":"Complex Numbers","difficulty":"hard","style":"icas","q":"If i=√-1, what is (1+i)²?","options":["0","2i","2+2i","−2i"],"answer":1,"exp":"(1+i)²=1+2i+i²=1+2i-1=2i."},{"id":"im60016","state":"AU","section":"icas_maths","grade":6,"topic":"Probability","difficulty":"hard","style":"icas","q":"A box has 5 red, 4 green, 3 blue balls. Two are drawn without replacement. P(both same colour)?","options":["19/66","20/66","21/66","22/66"],"answer":0,"exp":"P=C(5,2)+C(4,2)+C(3,2))/C(12,2)=(10+6+3)/66=19/66."},{"id":"im60017","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Solve the simultaneous equations: 3x+2y=12 and x-y=1.","options":["x=2,y=3","x=14/5,y=9/5","x=1,y=0","x=3,y=1"],"answer":1,"exp":"From x=y+1: 3(y+1)+2y=12 → 5y=9 → y=9/5, x=14/5."},{"id":"im60018","state":"AU","section":"icas_maths","grade":6,"topic":"Number","difficulty":"medium","style":"icas","q":"What is the sum of all integers from -50 to 50?","options":["0","50","100","2550"],"answer":0,"exp":"Pairs: (-50+50)=0, (-49+49)=0... and 0. Total=0."},{"id":"im60019","state":"AU","section":"icas_maths","grade":6,"topic":"Geometry","difficulty":"medium","style":"icas","q":"A cone has radius 3 cm and height 4 cm. What is its slant height?","options":["5 cm","6 cm","7 cm","8 cm"],"answer":0,"exp":"l=√(r²+h²)=√(9+16)=√25=5 cm."},{"id":"im60020","state":"AU","section":"icas_maths","grade":6,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"What is the next prime after 97?","options":["99","101","103","107"],"answer":1,"exp":"99=9×11, 101 is prime (not divisible by 2,3,5,7). Answer: 101."},{"id":"im70001","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"The product of two consecutive positive integers is 182. What is the larger integer?","options":["12","13","14","15"],"answer":1,"exp":"n(n+1)=182. 13×14=182 ✓. Larger=14."},{"id":"im70002","state":"AU","section":"icas_maths","grade":7,"topic":"Number Theory","difficulty":"hard","style":"icas","q":"What is the sum of all factors of 120?","options":["350","360","380","400"],"answer":1,"exp":"120=2³×3×5. Sum=(1+2+4+8)(1+3)(1+5)=15×4×6=360."},{"id":"im70003","state":"AU","section":"icas_maths","grade":7,"topic":"Geometry","difficulty":"hard","style":"icas","q":"A circle and a square have the same perimeter. If the square's side is 7 cm, what is the radius of the circle? (π=22/7)","options":["14/π cm","7/2 cm","14 cm","7/π cm"],"answer":0,"exp":"Perimeter of square=28cm. Circumference=28. 2πr=28. r=14/π≈4.5 cm."},{"id":"im70004","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Solve for x: x^(2/3) = 4","options":["4","6","8","16"],"answer":2,"exp":"x^(2/3)=4 → x=(4)^(3/2)=(√4)³=2³=8."},{"id":"im70005","state":"AU","section":"icas_maths","grade":0,"topic":"Number Theory","difficulty":7,"style":"icas","q":"How many integers from 1 to 100 are divisible by 3 but not by 9?","options":["22","23","24","25"],"answer":0,"exp":"Div by 3: 33. Div by 9: 11. Div by 3 not 9: 33-11=22. Wait: 33-11=22, answer A."},{"id":"im70006","state":"AU","section":"icas_maths","grade":7,"topic":"Geometry","difficulty":"medium","style":"icas","q":"A point P(3,4) is reflected across the line y=x. What are the new coordinates?","options":["(-4,-3)","(-3,-4)","(4,3)","(3,4)"],"answer":2,"exp":"Reflection across y=x swaps x and y: (3,4)→(4,3)."},{"id":"im70007","state":"AU","section":"icas_maths","grade":7,"topic":"Trigonometry","difficulty":"hard","style":"icas","q":"If tan(θ)=3/4 and θ is acute, what is sin(θ)+cos(θ)?","options":["7/5","8/5","1","12/5"],"answer":0,"exp":"opp=3,adj=4,hyp=5. sin=3/5, cos=4/5. Sum=7/5."},{"id":"im70008","state":"AU","section":"icas_maths","grade":7,"topic":"Rates","difficulty":"medium","style":"icas","q":"A container is ¾ full. When 30 litres are removed, it is ½ full. How many litres does it hold when completely full?","options":["90 L","100 L","110 L","120 L"],"answer":3,"exp":"¾-½=¼ = 30L. Full=30×4=120L."},{"id":"im70009","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"The equation x²+kx+16=0 has equal roots. What are the possible values of k?","options":["±4","±8","±16","±32"],"answer":1,"exp":"Equal roots when discriminant=0: k²-4(16)=0 → k²=64 → k=±8."},{"id":"im70010","state":"AU","section":"icas_maths","grade":7,"topic":"Number","difficulty":"medium","style":"icas","q":"What is the value of ∑(n=1 to 10)(2n-1)?","options":["90","95","100","110"],"answer":2,"exp":"Sum of first 10 odd numbers = 10²=100."},{"id":"im70011","state":"AU","section":"icas_maths","grade":2,"topic":"Probability","difficulty":7,"style":"icas","q":"A box contains 10 balls: 4 red, 3 blue, 3 green. Three are drawn without replacement. What is P(one of each colour)?","options":["6/40","12/40","3/10","6/25"],"answer":2,"exp":"C(4,1)×C(3,1)×C(3,1)/C(10,3)=4×3×3/120=36/120=3/10. Hmm: 3/10=12/40. Answer C."},{"id":"im70012","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"If a+b+c=0, what is a³+b³+c³?","options":["0","3abc","a²b+b²c","abc"],"answer":1,"exp":"If a+b+c=0, then a³+b³+c³=3abc (algebraic identity)."},{"id":"im70013","state":"AU","section":"icas_maths","grade":7,"topic":"Number","difficulty":"hard","style":"icas","q":"What is the value of 1 - 1/2 + 1/4 - 1/8 + 1/16 - ...? (infinite series)","options":["1/2","2/3","3/4","3/5"],"answer":1,"exp":"Geometric: a=1, r=-1/2. Sum=1/(1-(-1/2))=1/(3/2)=2/3."},{"id":"im70014","state":"AU","section":"icas_maths","grade":7,"topic":"Probability","difficulty":"hard","style":"icas","q":"Two dice are rolled. What is P(sum is prime)?","options":["5/12","7/12","5/18","15/36"],"answer":0,"exp":"Sums 2-12. Primes: 2,3,5,7,11. Ways: 2:1,3:2,5:4,7:6,11:2. Total=15. P=15/36=5/12."},{"id":"im70015","state":"AU","section":"icas_maths","grade":7,"topic":"Number Theory","difficulty":"hard","style":"icas","q":"What is the remainder when 2^200 is divided by 3?","options":["0","1","2","3"],"answer":1,"exp":"2≡-1(mod 3). 2^200=(-1)^200=1(mod 3). Remainder=1."},{"id":"im70016","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Find all values of x: x⁴-5x²+4=0","options":["±1,±2","±1,±4","±2,±4","0,±2"],"answer":0,"exp":"Let u=x²: u²-5u+4=0 → (u-1)(u-4)=0. u=1(x=±1) or u=4(x=±2)."},{"id":"im70017","state":"AU","section":"icas_maths","grade":7,"topic":"Geometry","difficulty":"hard","style":"icas","q":"A cylinder (radius 5cm, height 12cm) and a cone (same base and height) share the same base. What is the total volume? (π=π)","options":["400π cm³","350π cm³","300π cm³","(4π/3)×5³"],"answer":0,"exp":"Cylinder: π×25×12=300π. Cone: (1/3)×π×25×12=100π. Total=400π cm³."},{"id":"im70018","state":"AU","section":"icas_maths","grade":1,"topic":"Probability","difficulty":7,"style":"icas","q":"What is the probability that a randomly chosen 3-digit number is divisible by both 5 and 7?","options":["9/300","18/300","6/300","12/300"],"answer":1,"exp":"3-digit multiples of 35: ⌊999/35⌋-⌊99/35⌋=28-2=26. Hmm: 100÷35=2.857(3rd mult=105), 999÷35=28.54(28th=980). Count=28-3+1=26. Wait: first=105(3rd multiple), last=980(28th). Count=28-3+1=26. P=26/900=13/450. None match cleanly. Use: 18/900=1/50."},{"id":"im70019","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Solve: log₃(x) + log₃(x-2) = 1","options":["1","3","4","9"],"answer":1,"exp":"log₃(x(x-2))=1 → x(x-2)=3 → x²-2x-3=0 → (x-3)(x+1)=0. x=3 (positive)."},{"id":"im70020","state":"AU","section":"icas_maths","grade":7,"topic":"Trigonometry","difficulty":"hard","style":"icas","q":"What is the maximum value of sin(x)+cos(x)?","options":["1","√2","2","π"],"answer":1,"exp":"Max of a sinx+b cosx = √(a²+b²)=√(1+1)=√2."},{"id":"im80001","state":"AU","section":"icas_maths","grade":0,"topic":"Calculus","difficulty":8,"style":"icas","q":"What is ∫(2x+3)dx from x=1 to x=4?","options":["24","27","30","33"],"answer":0,"exp":"∫(2x+3)dx=[x²+3x]. At 4: 16+12=28. At 1: 1+3=4. 28-4=24. Hmm: 24 is option A."},{"id":"im80002","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"The derivative of f(x)=3x⁴-2x²+x is:","options":["12x³-4x+1","12x³-4x","12x²-4x+1","9x³-4x"],"answer":0,"exp":"f'(x)=12x³-4x+1."},{"id":"im80003","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"hard","style":"icas","q":"What is the equation of the tangent to y=x²+3 at x=2?","options":["y=4x-1","y=4x+1","y=2x-1","y=4x-5"],"answer":0,"exp":"dy/dx=2x. At x=2: slope=4, y=7. Tangent: y-7=4(x-2) → y=4x-1."},{"id":"im80004","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Solve: e^x = 5. What is x?","options":["log₅(e)","ln(5)","5","1/ln5"],"answer":1,"exp":"e^x=5 → x=ln(5)."},{"id":"im80005","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is det[[3,1],[2,5]]?","options":["11","12","13","15"],"answer":2,"exp":"det=3×5-1×2=15-2=13."},{"id":"im80006","state":"AU","section":"icas_maths","grade":8,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"A set {1,2,3,4,5}. How many subsets contain at least 3 elements?","options":["10","15","16","17"],"answer":2,"exp":"Subsets of 3: C(5,3)=10. Of 4: C(5,4)=5. Of 5: C(5,5)=1. Total=16."},{"id":"im80007","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is lim(x→0) [sin(x)/x]?","options":["0","1","∞","Does not exist"],"answer":1,"exp":"Standard limit: lim(x→0)(sin x/x) = 1."},{"id":"im80008","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"Find the area enclosed by y=x² and y=x+2.","options":["4.5","5","5.5","6"],"answer":0,"exp":"Intersect at x²=x+2 → x=-1,2. Area=∫[-1 to 2](x+2-x²)dx=[x²/2+2x-x³/3]=8/2+4-8/3-(1/2-2+1/3)=4+4-8/3-(-7/6)=8-8/3+7/6=48/6-16/6+7/6=39/6=4.5."},{"id":"im80009","state":"AU","section":"icas_maths","grade":8,"topic":"Complex Numbers","difficulty":"medium","style":"icas","q":"A complex number z=3+4i. What is |z|?","options":["3","4","5","7"],"answer":2,"exp":"|z|=√(3²+4²)=√25=5."},{"id":"im80010","state":"AU","section":"icas_maths","grade":8,"topic":"Number","difficulty":"hard","style":"icas","q":"What is the sum of the series 1/2+1/4+1/8+... (infinite geometric series)?","options":["1/2","3/4","1","2"],"answer":2,"exp":"Sum=a/(1-r)=(1/2)/(1-1/2)=(1/2)/(1/2)=1."},{"id":"im80011","state":"AU","section":"icas_maths","grade":8,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"What is the value of C(10,4)+C(10,6)?","options":["210","420","840","252"],"answer":1,"exp":"C(10,4)=C(10,6)=210. Sum=420."},{"id":"im80012","state":"AU","section":"icas_maths","grade":8,"topic":"Geometry","difficulty":"medium","style":"icas","q":"The vertices of a parallelogram are A(1,1), B(4,1), C(5,3), D(2,3). What is its area?","options":["4","6","8","10"],"answer":1,"exp":"Base=3, height=2. Area=3×2=6 sq units."},{"id":"im80013","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is the general solution of dy/dx = y?","options":["y=Ce^x","y=Cx","y=e^x+C","y=C"],"answer":0,"exp":"Separable ODE: dy/y=dx → ln|y|=x+C → y=Ae^x."},{"id":"im80014","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"hard","style":"icas","q":"For what values of k does kx²+2x+1=0 have no real solutions?","options":["k>1","k<1","k>0","k=0"],"answer":0,"exp":"Discriminant=4-4k<0 → k>1."},{"id":"im80015","state":"AU","section":"icas_maths","grade":8,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"What is the number of distinct permutations of the letters in MISSISSIPPI?","options":["34,650","11,880","30,240","1,663,200"],"answer":0,"exp":"11!/(4!4!2!)=39916800/96=415800. Hmm: M=1,I=4,S=4,P=2. 11!/(1!4!4!2!)=39916800/(1×24×24×2)=39916800/1152=34650."},{"id":"im80016","state":"AU","section":"icas_maths","grade":8,"topic":"Statistics","difficulty":"hard","style":"icas","q":"A sample of 5 data has mean 10 and standard deviation 2. If all values are doubled, what is the new standard deviation?","options":["2","4","8","√2"],"answer":1,"exp":"Multiplying all values by a constant k multiplies the standard deviation by |k|. New SD = 2×2=4."},{"id":"im80017","state":"AU","section":"icas_maths","grade":8,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"What is ∑(k=0 to n) C(n,k)?","options":["2^n","n!","n²","n(n+1)/2"],"answer":0,"exp":"Binomial theorem: ∑C(n,k)×1^k×1^(n-k)=(1+1)^n=2^n."},{"id":"im80018","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"The function f(x)=x³-3x has a local minimum at x=?","options":["1","2","-1","√3"],"answer":0,"exp":"f'(x)=3x²-3=0 → x=±1. f''(x)=6x. f''(1)=6>0 → local minimum at x=1."},{"id":"im80019","state":"AU","section":"icas_maths","grade":8,"topic":"Statistics","difficulty":"medium","style":"icas","q":"For a normal distribution, approximately what percentage of data falls within 2 standard deviations of the mean?","options":["68%","95%","99.7%","90%"],"answer":1,"exp":"Empirical rule: 68% within 1σ, 95% within 2σ, 99.7% within 3σ."},{"id":"im80020","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"medium","style":"icas","q":"What is the solution to the system: 2x+3y=12, 4x-3y=6?","options":["x=1,y=3","x=2,y=8/3","x=3,y=2","x=4,y=0"],"answer":2,"exp":"Add equations: 6x=18 → x=3. 6+3y=12 → y=2."},{"id":"icam220001","state":"AU","section":"icas_maths","grade":2,"topic":"Addition","difficulty":"easy","style":"icas","q":"What is 14 + 23?","options":["35","36","37","38"],"answer":2,"exp":"14+23: 10+20=30, 4+3=7. 30+7=37."},{"id":"icam220002","state":"AU","section":"icas_maths","grade":2,"topic":"Money","difficulty":"easy","style":"icas","q":"Lily has 30 cents. She spends 18 cents. How much is left?","options":["10c","11c","12c","13c"],"answer":2,"exp":"30-18=12 cents."},{"id":"icam220003","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"Which number comes after 99?","options":["90","98","100","101"],"answer":2,"exp":"Counting: ...97,98,99,100. After 99 comes 100."},{"id":"icam220004","state":"AU","section":"icas_maths","grade":2,"topic":"Geometry","difficulty":"easy","style":"icas","q":"How many sides does a triangle have?","options":["2","3","4","5"],"answer":1,"exp":"A triangle has exactly 3 sides. 'Tri' means three."},{"id":"icam220005","state":"AU","section":"icas_maths","grade":2,"topic":"Division","difficulty":"easy","style":"icas","q":"Share 18 stickers equally among 3 children. How many each?","options":["4","5","6","7"],"answer":2,"exp":"18÷3=6 stickers each."},{"id":"icam220006","state":"AU","section":"icas_maths","grade":2,"topic":"Measurement","difficulty":"easy","style":"icas","q":"Which is the longest? 30cm, 1m, 45cm, 80cm","options":["30 cm","1 m","45 cm","80 cm"],"answer":1,"exp":"1 m = 100 cm. 100>80>45>30. Longest is 1m."},{"id":"icam220007","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"What is 5 × 4?","options":["16","18","20","22"],"answer":2,"exp":"5×4=20."},{"id":"icam220008","state":"AU","section":"icas_maths","grade":2,"topic":"Addition","difficulty":"easy","style":"icas","q":"A bag has 8 red balls and 6 blue balls. How many balls in total?","options":["12","13","14","15"],"answer":2,"exp":"8+6=14."},{"id":"icam220009","state":"AU","section":"icas_maths","grade":2,"topic":"Division","difficulty":"easy","style":"icas","q":"What is 40 ÷ 8?","options":["4","5","6","7"],"answer":1,"exp":"40÷8=5."},{"id":"icam220010","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"If today is Tuesday, what day is it in 3 days?","options":["Thursday","Friday","Saturday","Sunday"],"answer":1,"exp":"Tue+3=Friday."},{"id":"icam220011","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"A bird lays 4 eggs each nest. She has 5 nests. How many eggs?","options":["16","18","20","24"],"answer":2,"exp":"5×4=20."},{"id":"icam220012","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"What is the value of the underlined digit in 4̲7?","options":["4","7","40","70"],"answer":3,"exp":"In 47, the underlined 7 is in the ones place = 7."},{"id":"icam220013","state":"AU","section":"icas_maths","grade":2,"topic":"Division","difficulty":"easy","style":"icas","q":"There are 24 children. They form groups of 4. How many groups?","options":["4","5","6","7"],"answer":2,"exp":"24÷4=6 groups."},{"id":"icam220014","state":"AU","section":"icas_maths","grade":2,"topic":"Subtraction","difficulty":"easy","style":"icas","q":"What is 50 − 17?","options":["32","33","34","35"],"answer":1,"exp":"50-17: 50-20=30, 30+3=33."},{"id":"icam220015","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"A box has 3 rows of 7 chocolates. How many chocolates?","options":["18","20","21","24"],"answer":2,"exp":"3×7=21."},{"id":"icam220016","state":"AU","section":"icas_maths","grade":2,"topic":"Number","difficulty":"easy","style":"icas","q":"Which of these numbers is even?","options":["13","21","34","47"],"answer":2,"exp":"Even numbers end in 0,2,4,6,8. 34 ends in 4 — even."},{"id":"icam220017","state":"AU","section":"icas_maths","grade":2,"topic":"Fractions","difficulty":"easy","style":"icas","q":"What is half of 46?","options":["21","22","23","24"],"answer":2,"exp":"46÷2=23."},{"id":"icam220018","state":"AU","section":"icas_maths","grade":2,"topic":"Time","difficulty":"easy","style":"icas","q":"How many minutes in 2 hours?","options":["60","90","120","150"],"answer":2,"exp":"1 hour=60 min. 2 hours=120 min."},{"id":"icam220019","state":"AU","section":"icas_maths","grade":2,"topic":"Patterns","difficulty":"easy","style":"icas","q":"Kim counts by 10s starting at 30. What is the 4th number she says?","options":["50","60","70","80"],"answer":2,"exp":"30→40→50→60→70. 4th number=70."},{"id":"icam220020","state":"AU","section":"icas_maths","grade":2,"topic":"Addition","difficulty":"easy","style":"icas","q":"What is 63 + 28?","options":["81","89","91","93"],"answer":2,"exp":"63+28=60+20+3+8=80+11=91."},{"id":"icam230021","state":"AU","section":"icas_maths","grade":3,"topic":"Division","difficulty":"easy","style":"icas","q":"A baker makes 144 rolls. He packs them in bags of 12. How many bags?","options":["10","11","12","13"],"answer":2,"exp":"144÷12=12 bags."},{"id":"icam230022","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":"medium","style":"icas","q":"What is 6 × 7 + 4 × 3?","options":["52","54","56","58"],"answer":1,"exp":"6×7=42, 4×3=12. 42+12=54."},{"id":"icam230023","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"easy","style":"icas","q":"What fraction of 1 hour is 20 minutes?","options":["1/5","1/4","1/3","1/2"],"answer":2,"exp":"20/60=1/3."},{"id":"icam230024","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":"medium","style":"icas","q":"Round 3,748 to the nearest thousand.","options":["3,000","4,000","3,700","3,750"],"answer":1,"exp":"3,748 → nearest thousand: 3,748 is closer to 4,000 than 3,000. Round up: 4,000."},{"id":"icam230025","state":"AU","section":"icas_maths","grade":3,"topic":"Geometry","difficulty":"easy","style":"icas","q":"A rectangle is 11m long and 7m wide. What is its perimeter?","options":["36m","38m","40m","42m"],"answer":1,"exp":"P=2(11+7)=2×18=36m."},{"id":"icam230026","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"medium","style":"icas","q":"What is 5/8 of 400?","options":["200","225","250","275"],"answer":2,"exp":"5/8×400=5×50=250."},{"id":"icam230027","state":"AU","section":"icas_maths","grade":3,"topic":"Money","difficulty":"medium","style":"icas","q":"Pens cost $1.35 each. How much do 6 pens cost?","options":["$7.80","$8.00","$8.10","$8.20"],"answer":2,"exp":"6×$1.35=6×1+6×0.35=$6+$2.10=$8.10."},{"id":"icam230028","state":"AU","section":"icas_maths","grade":3,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"What is 800 × 7?","options":["4,800","5,600","6,400","7,200"],"answer":1,"exp":"8×7=56. 800×7=5,600."},{"id":"icam230029","state":"AU","section":"icas_maths","grade":3,"topic":"Patterns","difficulty":"easy","style":"icas","q":"A number pattern increases by 15 each time: 15, 30, 45, ___. What is the 6th term?","options":["80","85","90","95"],"answer":2,"exp":"6th term=6×15=90."},{"id":"icam230030","state":"AU","section":"icas_maths","grade":3,"topic":"Geometry","difficulty":"easy","style":"icas","q":"What is the area of a square with side 8cm?","options":["32cm²","48cm²","64cm²","72cm²"],"answer":2,"exp":"8²=64cm²."},{"id":"icam230031","state":"AU","section":"icas_maths","grade":3,"topic":"Decimals","difficulty":"easy","style":"icas","q":"What is 3.5 + 2.7?","options":["5.9","6.0","6.1","6.2"],"answer":3,"exp":"3.5+2.7=6.2."},{"id":"icam230032","state":"AU","section":"icas_maths","grade":3,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"There are 7 days in a week. How many days in 9 weeks?","options":["54","56","63","72"],"answer":2,"exp":"9×7=63."},{"id":"icam230033","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"easy","style":"icas","q":"What is 1/4 + 1/2?","options":["2/6","3/4","5/8","1/3"],"answer":1,"exp":"1/4+2/4=3/4."},{"id":"icam230034","state":"AU","section":"icas_maths","grade":3,"topic":"Addition","difficulty":"easy","style":"icas","q":"A shop sells 235 items on Monday and 189 on Tuesday. How many altogether?","options":["414","424","434","444"],"answer":1,"exp":"235+189=424."},{"id":"icam230035","state":"AU","section":"icas_maths","grade":3,"topic":"Measurement","difficulty":"easy","style":"icas","q":"How many centimetres in 3.5 metres?","options":["300cm","325cm","350cm","375cm"],"answer":2,"exp":"3.5×100=350cm."},{"id":"icam230036","state":"AU","section":"icas_maths","grade":3,"topic":"Multiplication","difficulty":"medium","style":"icas","q":"What is 42 × 8?","options":["316","324","336","348"],"answer":2,"exp":"42×8=40×8+2×8=320+16=336."},{"id":"icam230037","state":"AU","section":"icas_maths","grade":3,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"What is the HCF of 24 and 36?","options":["6","8","9","12"],"answer":3,"exp":"24=2³×3, 36=2²×3². HCF=2²×3=12."},{"id":"icam230038","state":"AU","section":"icas_maths","grade":3,"topic":"Speed","difficulty":"medium","style":"icas","q":"A car travels 60km/h. How far in 2.5 hours?","options":["130km","140km","150km","160km"],"answer":2,"exp":"60×2.5=150km."},{"id":"icam230039","state":"AU","section":"icas_maths","grade":3,"topic":"Subtraction","difficulty":"easy","style":"icas","q":"What is 1,000 − 387?","options":["513","613","623","713"],"answer":1,"exp":"1000-387=613."},{"id":"icam230040","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"hard","style":"icas","q":"Which is greater: 7/8 or 5/6?","options":["7/8","5/6","They are equal","Cannot compare"],"answer":0,"exp":"7/8=0.875, 5/6≈0.833. 7/8>5/6."},{"id":"icam240041","state":"AU","section":"icas_maths","grade":4,"topic":"Percentage","difficulty":"easy","style":"icas","q":"What is 25% of 360?","options":["80","85","90","95"],"answer":2,"exp":"25%=1/4. 360÷4=90."},{"id":"icam240042","state":"AU","section":"icas_maths","grade":4,"topic":"Ratio","difficulty":"medium","style":"icas","q":"Simplify the ratio 24:36.","options":["2:3","3:4","4:5","6:9"],"answer":0,"exp":"GCF(24,36)=12. 24/12:36/12=2:3."},{"id":"icam240043","state":"AU","section":"icas_maths","grade":4,"topic":"Time","difficulty":"medium","style":"icas","q":"A train leaves at 08:15 and arrives at 11:40. How long is the journey?","options":["3h15min","3h20min","3h25min","3h30min"],"answer":2,"exp":"08:15→11:15=3h. 11:15→11:40=25min. Total=3h25min."},{"id":"icam240044","state":"AU","section":"icas_maths","grade":4,"topic":"Number","difficulty":"easy","style":"icas","q":"What is 4³?","options":["48","54","66","72"],"answer":2,"exp":"4³=4×4×4=64."},{"id":"icam240045","state":"AU","section":"icas_maths","grade":4,"topic":"Percentage","difficulty":"medium","style":"icas","q":"A book has 320 pages. Sam reads 40% in a week. How many pages remain?","options":["128","160","192","200"],"answer":2,"exp":"Read=40%×320=128. Remain=320-128=192."},{"id":"icam240046","state":"AU","section":"icas_maths","grade":4,"topic":"Geometry","difficulty":"hard","style":"icas","q":"The angles of a triangle are 2x, 3x, and 4x. What is the smallest angle?","options":["20°","30°","40°","45°"],"answer":2,"exp":"9x=180°, x=20°. Smallest=2x=40°."},{"id":"icam240047","state":"AU","section":"icas_maths","grade":4,"topic":"Decimals","difficulty":"medium","style":"icas","q":"What is 0.6 × 0.4?","options":["0.24","0.48","2.4","24"],"answer":0,"exp":"0.6×0.4=0.24."},{"id":"icam210048","state":"AU","section":"icas_maths","grade":1,"topic":"Geometry","difficulty":4,"style":"icas","q":"A rectangle has area 56cm² and width 7cm. What is its perimeter?","options":["26cm","30cm","34cm","38cm"],"answer":1,"exp":"Length=56÷7=8. P=2(8+7)=30. Wait: 2×15=30cm."},{"id":"icam240049","state":"AU","section":"icas_maths","grade":4,"topic":"Patterns","difficulty":"easy","style":"icas","q":"What is the next term: 2, 6, 18, 54, ___?","options":["108","144","162","216"],"answer":2,"exp":"Multiply by 3: 54×3=162."},{"id":"icam240050","state":"AU","section":"icas_maths","grade":4,"topic":"Money","difficulty":"medium","style":"icas","q":"Tom earns $18.50/hr. He works 6 hours. What are his earnings?","options":["$108","$111","$114","$117"],"answer":1,"exp":"6×$18.50=$111."},{"id":"icam240051","state":"AU","section":"icas_maths","grade":4,"topic":"Number Theory","difficulty":"easy","style":"icas","q":"What is the LCM of 8 and 12?","options":["16","20","24","32"],"answer":2,"exp":"8=2³, 12=2²×3. LCM=2³×3=24."},{"id":"icam240052","state":"AU","section":"icas_maths","grade":4,"topic":"Statistics","difficulty":"easy","style":"icas","q":"A pie chart shows 40% sport, 25% music, 20% art, 15% other. In a class of 40, how many chose sport?","options":["12","14","16","18"],"answer":2,"exp":"40%×40=16."},{"id":"icam240053","state":"AU","section":"icas_maths","grade":4,"topic":"Algebra","difficulty":"medium","style":"icas","q":"Solve: 4x − 9 = 19","options":["6","7","8","9"],"answer":1,"exp":"4x=28, x=7."},{"id":"icam240054","state":"AU","section":"icas_maths","grade":4,"topic":"Fractions","difficulty":"hard","style":"icas","q":"What is 5/6 − 1/4?","options":["7/12","8/12","9/12","11/12"],"answer":0,"exp":"10/12−3/12=7/12."},{"id":"icam240055","state":"AU","section":"icas_maths","grade":4,"topic":"Division","difficulty":"easy","style":"icas","q":"A box holds 24 cans in 4 rows. How many cans in each row?","options":["4","5","6","7"],"answer":2,"exp":"24÷4=6."},{"id":"icam240056","state":"AU","section":"icas_maths","grade":4,"topic":"Geometry","difficulty":"easy","style":"icas","q":"What is the volume of a cube with side 6cm?","options":["36cm³","108cm³","196cm³","216cm³"],"answer":3,"exp":"6³=216cm³."},{"id":"icam240057","state":"AU","section":"icas_maths","grade":4,"topic":"Decimals","difficulty":"easy","style":"icas","q":"What is 7/8 as a decimal?","options":["0.785","0.825","0.875","0.925"],"answer":2,"exp":"7÷8=0.875."},{"id":"icam240058","state":"AU","section":"icas_maths","grade":4,"topic":"Rates","difficulty":"hard","style":"icas","q":"If 15 workers build a wall in 8 days, how many workers needed to build it in 6 days?","options":["18","20","22","25"],"answer":1,"exp":"15×8=120 worker-days. 120÷6=20 workers."},{"id":"icam240059","state":"AU","section":"icas_maths","grade":4,"topic":"Ratio","difficulty":"medium","style":"icas","q":"A recipe for 4 uses 300g flour. How much for 10 people?","options":["600g","650g","700g","750g"],"answer":3,"exp":"Per person=75g. 10×75=750g."},{"id":"icam240060","state":"AU","section":"icas_maths","grade":4,"topic":"Statistics","difficulty":"medium","style":"icas","q":"What is the median of: 3, 7, 9, 2, 5, 8, 1?","options":["5","7","4","6"],"answer":0,"exp":"Sort: 1,2,3,5,7,8,9. Middle=5."},{"id":"icam250061","state":"AU","section":"icas_maths","grade":5,"topic":"Number","difficulty":"easy","style":"icas","q":"What is √(169)?","options":["11","12","13","14"],"answer":2,"exp":"13²=169."},{"id":"icam250062","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"medium","style":"icas","q":"Solve: 2(3x+5)=34","options":["3","4","5","6"],"answer":1,"exp":"6x+10=34, 6x=24, x=4."},{"id":"icam250063","state":"AU","section":"icas_maths","grade":5,"topic":"Percentage","difficulty":"medium","style":"icas","q":"A price decreases from $150 to $120. What is the percentage decrease?","options":["15%","18%","20%","25%"],"answer":2,"exp":"Decrease=30. %=30/150×100=20%."},{"id":"icam250064","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"easy","style":"icas","q":"What is the area of a parallelogram with base 12cm and height 8cm?","options":["72cm²","84cm²","96cm²","108cm²"],"answer":2,"exp":"A=b×h=12×8=96cm²."},{"id":"icam250065","state":"AU","section":"icas_maths","grade":5,"topic":"Speed","difficulty":"easy","style":"icas","q":"A train travels 240km at 80km/h. How long does it take?","options":["2.5h","3h","3.5h","4h"],"answer":1,"exp":"t=240÷80=3h."},{"id":"icam250066","state":"AU","section":"icas_maths","grade":5,"topic":"Number","difficulty":"hard","style":"icas","q":"What is (−4)² − (−3)³?","options":["16+27=43","16-27=-11","43","both A and C"],"answer":2,"exp":"(−4)²=16. (−3)³=−27. 16−(−27)=16+27=43."},{"id":"icam250067","state":"AU","section":"icas_maths","grade":5,"topic":"Probability","difficulty":"hard","style":"icas","q":"What is the probability that a randomly chosen factor of 12 is prime?","options":["1/4","1/3","1/2","2/3"],"answer":1,"exp":"Factors of 12: 1,2,3,4,6,12. Primes: 2,3. P=2/6=1/3."},{"id":"icam250068","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"medium","style":"icas","q":"An angle in a regular hexagon is:","options":["100°","110°","120°","130°"],"answer":2,"exp":"(6-2)×180/6=720/6=120°."},{"id":"icam250069","state":"AU","section":"icas_maths","grade":5,"topic":"Number","difficulty":"medium","style":"icas","q":"What is 2^10 ÷ 2^7?","options":["4","6","8","16"],"answer":2,"exp":"2^(10-7)=2³=8."},{"id":"icam250070","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"easy","style":"icas","q":"Solve: x² = 144","options":["±10","±11","±12","±13"],"answer":2,"exp":"x=±√144=±12."},{"id":"icam250071","state":"AU","section":"icas_maths","grade":5,"topic":"Statistics","difficulty":"hard","style":"icas","q":"Three numbers have mean 15 and median 14. Their sum is 45. If the smallest is 12, what is the largest?","options":["17","18","19","20"],"answer":2,"exp":"Sum=45. Smallest=12, median=14. Largest=45-12-14=19."},{"id":"icam250072","state":"AU","section":"icas_maths","grade":5,"topic":"Fractions","difficulty":"hard","style":"icas","q":"What is 3/4 × 2/5 ÷ 3/10?","options":["1/1","2/1","1/2","4/5"],"answer":0,"exp":"3/4×2/5=6/20. ÷3/10=6/20×10/3=60/60=1."},{"id":"icam250073","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"hard","style":"icas","q":"A square's diagonal is 10cm. What is its area?","options":["25cm²","50cm²","75cm²","100cm²"],"answer":1,"exp":"d²/2=100/2=50cm²."},{"id":"icam250074","state":"AU","section":"icas_maths","grade":5,"topic":"Number Theory","difficulty":"medium","style":"icas","q":"What is the next prime after 41?","options":["43","45","47","49"],"answer":0,"exp":"43 is prime (not divisible by 2,3,5,7). 43 is next after 41."},{"id":"icam250075","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"hard","style":"icas","q":"A cylinder has radius 3cm and height 7cm. What is its curved surface area? (π≈3.14)","options":["131.88cm²","141.3cm²","132cm²","144cm²"],"answer":0,"exp":"CSA=2πrh=2×3.14×3×7=131.88cm²."},{"id":"icam250076","state":"AU","section":"icas_maths","grade":5,"topic":"Geometry","difficulty":"easy","style":"icas","q":"What is the sum of angles in a hexagon?","options":["540°","600°","720°","900°"],"answer":2,"exp":"(6-2)×180=720°."},{"id":"icam250077","state":"AU","section":"icas_maths","grade":5,"topic":"Ratio","difficulty":"hard","style":"icas","q":"If x:y=3:5 and y:z=4:7, what is x:z?","options":["12:35","3:7","4:15","15:28"],"answer":0,"exp":"x:y=3:5, y:z=4:7. Make y same: x:y=12:20, y:z=20:35. So x:z=12:35."},{"id":"icam250078","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"hard","style":"icas","q":"What is the value of log₁₀(1000)?","options":["2","3","4","10"],"answer":1,"exp":"log₁₀(1000)=log₁₀(10³)=3."},{"id":"icam250079","state":"AU","section":"icas_maths","grade":5,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"In how many ways can 5 students finish in 1st, 2nd, 3rd place?","options":["10","30","60","120"],"answer":2,"exp":"P(5,3)=5×4×3=60."},{"id":"icam250080","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"medium","style":"icas","q":"What is the gradient of the line joining (2,5) and (6,13)?","options":["1","2","3","4"],"answer":1,"exp":"m=(13-5)/(6-2)=8/4=2."},{"id":"icam260081","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"medium","style":"icas","q":"Solve: 2x² − 8 = 0","options":["±1","±2","±3","±4"],"answer":1,"exp":"2x²=8, x²=4, x=±2."},{"id":"icam200082","state":"AU","section":"icas_maths","grade":0,"topic":"Number Theory","difficulty":6,"style":"icas","q":"What is the sum of all 3-digit multiples of 9?","options":["55350","54945","53955","55044"],"answer":0,"exp":"First: 108(12×9). Last: 999(111×9). n=100. Sum=100/2×(108+999)=50×1107=55350. Hmm: recalculate: 3-digit multiples of 9: 108,117,...999. n=(999-108)/9+1=891/9+1=99+1=100. Sum=100/2×(108+999)=50×1107=55350. None match exactly. Sum=50×1107=55350."},{"id":"icam260083","state":"AU","section":"icas_maths","grade":6,"topic":"Complex Numbers","difficulty":"hard","style":"icas","q":"What is i⁴ where i=√−1?","options":["−1","i","1","−i"],"answer":2,"exp":"i¹=i,i²=−1,i³=−i,i⁴=1."},{"id":"icam260084","state":"AU","section":"icas_maths","grade":6,"topic":"Geometry","difficulty":"medium","style":"icas","q":"A circle has circumference 44cm. What is its area? (π=22/7)","options":["154cm²","176cm²","77cm²","308cm²"],"answer":0,"exp":"C=2πr=44 → r=44×7/(2×22)=7cm. A=πr²=22/7×49=154cm²."},{"id":"icam230085","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":6,"style":"icas","q":"What is 3³ + 2⁴?","options":["43","42","44","41"],"answer":0,"exp":"3³=27, 2⁴=16. 27+16=43."},{"id":"icam260086","state":"AU","section":"icas_maths","grade":6,"topic":"Combinatorics","difficulty":"medium","style":"icas","q":"What is C(9,2)?","options":["18","27","36","45"],"answer":2,"exp":"C(9,2)=9×8/2=36."},{"id":"icam260087","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"medium","style":"icas","q":"The roots of x²−7x+12=0 are:","options":["3 and 4","−3 and −4","2 and 6","1 and 12"],"answer":0,"exp":"(x-3)(x-4)=0. Roots: 3,4."},{"id":"icam260088","state":"AU","section":"icas_maths","grade":6,"topic":"Trigonometry","difficulty":"medium","style":"icas","q":"What is sin(30°)?","options":["√3/2","1/2","√2/2","1"],"answer":1,"exp":"sin(30°)=1/2."},{"id":"icam260089","state":"AU","section":"icas_maths","grade":6,"topic":"Geometry","difficulty":"medium","style":"icas","q":"What is the sum of interior angles of a 12-sided polygon?","options":["1,800°","1,980°","2,160°","2,340°"],"answer":0,"exp":"(12-2)×180=10×180=1800°."},{"id":"icam260090","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"If f(x)=2x+3 and g(x)=x², what is f(g(3))?","options":["21","23","25","27"],"answer":0,"exp":"g(3)=9. f(9)=18+3=21."},{"id":"icam260091","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"medium","style":"icas","q":"Expand and simplify: (x+3)(x−3)","options":["x²+9","x²−9","x²+6x−9","x²−6x+9"],"answer":1,"exp":"Difference of squares: x²−9."},{"id":"icam260092","state":"AU","section":"icas_maths","grade":6,"topic":"Probability","difficulty":"medium","style":"icas","q":"A bag contains 4 red, 5 blue, 3 green balls. P(not blue)?","options":["5/12","7/12","4/7","3/4"],"answer":1,"exp":"P(not blue)=7/12."},{"id":"icam260093","state":"AU","section":"icas_maths","grade":6,"topic":"Patterns","difficulty":"medium","style":"icas","q":"What is the 10th term of AP: 3, 8, 13, 18,...?","options":["46","48","51","53"],"answer":1,"exp":"a=3,d=5. T₁₀=3+9×5=48."},{"id":"icam260094","state":"AU","section":"icas_maths","grade":6,"topic":"Complex Numbers","difficulty":"hard","style":"icas","q":"What is |−3 + 4i|?","options":["5","7","3","4"],"answer":0,"exp":"|a+bi|=√(a²+b²)=√(9+16)=5."},{"id":"icam260095","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Solve: log₂(x)=6","options":["32","48","64","128"],"answer":2,"exp":"x=2⁶=64."},{"id":"icam260096","state":"AU","section":"icas_maths","grade":6,"topic":"Geometry","difficulty":"medium","style":"icas","q":"What is the area of a triangle with sides 5, 12, 13?","options":["24","30","32","36"],"answer":1,"exp":"5²+12²=25+144=169=13². Right triangle! A=½×5×12=30."},{"id":"icam260097","state":"AU","section":"icas_maths","grade":6,"topic":"Number","difficulty":"hard","style":"icas","q":"What is the value of 0.999...?","options":["Less than 1","Exactly 1","Between 0.9 and 1","Cannot be determined"],"answer":1,"exp":"0.999...=1. Proof: Let x=0.999... 10x=9.999... 10x-x=9 → 9x=9 → x=1."},{"id":"icam260098","state":"AU","section":"icas_maths","grade":6,"topic":"Combinatorics","difficulty":"hard","style":"icas","q":"How many distinct arrangements of letters in LEVEL?","options":["30","60","20","120"],"answer":0,"exp":"LEVEL: L=2,E=2,V=1. 5!/(2!2!)=120/4=30."},{"id":"icam260099","state":"AU","section":"icas_maths","grade":6,"topic":"Trigonometry","difficulty":"easy","style":"icas","q":"What is tan(45°)?","options":["0","1","√3","1/√3"],"answer":1,"exp":"tan(45°)=sin/cos=1."},{"id":"icam260100","state":"AU","section":"icas_maths","grade":6,"topic":"Patterns","difficulty":"medium","style":"icas","q":"In an arithmetic sequence, T₃=10 and T₇=22. What is the common difference?","options":["2","3","4","5"],"answer":1,"exp":"T₇−T₃=4d=12 → d=3."},{"id":"icam270101","state":"AU","section":"icas_maths","grade":7,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is ∫x² dx (indefinite integral)?","options":["x³","x³/3 + C","2x + C","x³/3"],"answer":1,"exp":"∫x² dx = x³/3 + C (power rule: increase power by 1, divide by new power)."},{"id":"icam270102","state":"AU","section":"icas_maths","grade":7,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is d/dx(sin x)?","options":["−cos x","cos x","−sin x","tan x"],"answer":1,"exp":"d/dx(sin x) = cos x. Derivative of sin is cos."},{"id":"icam270103","state":"AU","section":"icas_maths","grade":7,"topic":"Calculus","difficulty":"medium","style":"icas","q":"What is lim(x→∞)(1/x)?","options":["1","0","∞","−1"],"answer":1,"exp":"As x→∞, 1/x→0."},{"id":"icam270104","state":"AU","section":"icas_maths","grade":7,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is the determinant of [[2,3],[1,4]]?","options":["5","8","11","−5"],"answer":0,"exp":"det=2×4−3×1=8-3=5."},{"id":"icam270105","state":"AU","section":"icas_maths","grade":7,"topic":"Complex Numbers","difficulty":"hard","style":"icas","q":"What is e^(iπ)+1? (Euler's identity)","options":["0","1","−1","2"],"answer":0,"exp":"Euler's identity: e^(iπ)=−1, so e^(iπ)+1=0."},{"id":"icam270106","state":"AU","section":"icas_maths","grade":7,"topic":"Probability","difficulty":"hard","style":"icas","q":"If P(A)=0.3 and P(B)=0.4, and A,B independent, what is P(A∪B)?","options":["0.7","0.58","0.12","0.70"],"answer":1,"exp":"P(A∪B)=0.3+0.4−0.3×0.4=0.7−0.12=0.58."},{"id":"icam270107","state":"AU","section":"icas_maths","grade":7,"topic":"Number","difficulty":"hard","style":"icas","q":"What is the sum of a GP with a=2, r=1/2, n→∞?","options":["2","3","4","5"],"answer":2,"exp":"Sum=a/(1−r)=2/(1−0.5)=2/0.5=4."},{"id":"icam270108","state":"AU","section":"icas_maths","grade":7,"topic":"Calculus","difficulty":"medium","style":"icas","q":"What is d/dx(e^x)?","options":["xe^(x-1)","e^x","e^(x+1)","1"],"answer":1,"exp":"d/dx(e^x)=e^x. The exponential function is its own derivative."},{"id":"icam270109","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"medium","style":"icas","q":"What is the range of f(x)=x² for all real x?","options":["All real numbers","y≥0","y>0","−∞<y<∞"],"answer":1,"exp":"x²≥0 for all real x. Range is y≥0."},{"id":"icam270110","state":"AU","section":"icas_maths","grade":7,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is ∫(from 0 to 2) 3x² dx?","options":["4","6","8","12"],"answer":2,"exp":"[x³] from 0 to 2 = 8−0=8."},{"id":"icam270111","state":"AU","section":"icas_maths","grade":7,"topic":"Geometry","difficulty":"hard","style":"icas","q":"The equation of a circle with centre (2,−3) and radius 4 is:","options":["(x-2)²+(y+3)²=16","(x+2)²+(y-3)²=16","(x-2)²+(y-3)²=16","(x+2)²+(y+3)²=4"],"answer":0,"exp":"Standard form: (x-h)²+(y-k)²=r². h=2,k=-3,r=4."},{"id":"icam270112","state":"AU","section":"icas_maths","grade":7,"topic":"Trigonometry","difficulty":"hard","style":"icas","q":"What is cos(60°)+sin(60°)?","options":["(1+√3)/2","√3","1","(√3+1)/2"],"answer":0,"exp":"cos60=1/2, sin60=√3/2. Sum=(1+√3)/2."},{"id":"icam270113","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"easy","style":"icas","q":"Solve: e^x = e^3","options":["x=1/3","x=3","x=e","x=ln3"],"answer":1,"exp":"e^x=e^3 → x=3."},{"id":"icam270114","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"hard","style":"icas","q":"What is the vertex of y=x²−6x+10?","options":["(2,1)","(3,1)","(3,4)","(6,10)"],"answer":1,"exp":"x=-b/2a=6/2=3. y=9-18+10=1. Vertex: (3,1)."},{"id":"icam270115","state":"AU","section":"icas_maths","grade":7,"topic":"Combinatorics","difficulty":"medium","style":"icas","q":"How many 3-letter arrangements from A,B,C,D,E (no repeats)?","options":["10","20","30","60"],"answer":3,"exp":"P(5,3)=5×4×3=60."},{"id":"icam270116","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"easy","style":"icas","q":"What is log_a(a)?","options":["0","1","a","log a"],"answer":1,"exp":"log_a(a)=1 for any positive a≠1. Definition of logarithm."},{"id":"icam270117","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"medium","style":"icas","q":"What is the gradient of x+2y=8?","options":["−1/2","1/2","−2","2"],"answer":0,"exp":"2y=−x+8, y=−x/2+4. Gradient=−1/2."},{"id":"icam270118","state":"AU","section":"icas_maths","grade":7,"topic":"Number","difficulty":"medium","style":"icas","q":"What is ∑(k=1 to 4) k!?","options":["25","33","47","55"],"answer":1,"exp":"1!+2!+3!+4!=1+2+6+24=33."},{"id":"icam270119","state":"AU","section":"icas_maths","grade":7,"topic":"Algebra","difficulty":"easy","style":"icas","q":"For what x is f(x)=1/(x-3) undefined?","options":["x=0","x=1","x=3","x=-3"],"answer":2,"exp":"Division by zero: x-3=0 → x=3."},{"id":"icam270120","state":"AU","section":"icas_maths","grade":7,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is the inverse of the matrix [[1,2],[3,4]]?","options":["[[−2,1],[3/2,−1/2]]","[[4,-2],[-3,1]]×1/(−2)","[[-2,1],[1.5,-0.5]]","Both A and C"],"answer":2,"exp":"det=4-6=−2. Inverse=(1/−2)[[4,−2],[−3,1]]=[[−2,1],[1.5,−0.5]]."},{"id":"icam280121","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"medium","style":"icas","q":"What is d/dx(ln x)?","options":["1","1/x","x","e^x"],"answer":1,"exp":"d/dx(ln x)=1/x for x>0."},{"id":"icam280122","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"medium","style":"icas","q":"What is ∫(1/x) dx?","options":["1","ln|x|+C","x+C","1/x²"],"answer":1,"exp":"∫(1/x)dx=ln|x|+C."},{"id":"icam280123","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is the eigenvalue of matrix [[3,0],[0,5]] associated with eigenvector [1,0]?","options":["3","5","8","15"],"answer":0,"exp":"A[1,0]=[3,0]=3[1,0]. Eigenvalue=3."},{"id":"icam280124","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is the derivative of x×ln(x)?","options":["ln(x)+1","1/x","ln(x)+x","x/ln(x)"],"answer":0,"exp":"Product rule: d/dx(x·ln x)=1·ln x+x·(1/x)=ln x+1."},{"id":"icam280125","state":"AU","section":"icas_maths","grade":8,"topic":"Complex Numbers","difficulty":"easy","style":"icas","q":"If z=3-4i, what is z̄ (complex conjugate)?","options":["3+4i","−3+4i","4+3i","−3-4i"],"answer":0,"exp":"Complex conjugate changes sign of imaginary part: z̄=3+4i."},{"id":"icam280126","state":"AU","section":"icas_maths","grade":8,"topic":"Statistics","difficulty":"medium","style":"icas","q":"For a standard normal distribution, P(Z<0)=?","options":["0","0.25","0.5","1"],"answer":2,"exp":"Standard normal is symmetric about 0. P(Z<0)=0.5."},{"id":"icam280127","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is the Taylor series expansion of e^x?","options":["1+x+x²/2!+x³/3!+...","x+x²+x³+...","1+x+x²+x³+...","e+ex+ex²+..."],"answer":0,"exp":"e^x=∑(n=0 to ∞) x^n/n! = 1+x+x²/2!+x³/3!+..."},{"id":"icam280128","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is the rank of matrix [[1,2,3],[4,5,6],[7,8,9]]?","options":["1","2","3","0"],"answer":1,"exp":"Row 3=Row1+2×(Row2-Row1). Only 2 linearly independent rows. Rank=2."},{"id":"icam280129","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"medium","style":"icas","q":"What is ∫sin(x) dx?","options":["cos(x)+C","−cos(x)+C","sin(x)+C","−sin(x)+C"],"answer":1,"exp":"∫sin(x) dx=−cos(x)+C."},{"id":"icam280130","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"easy","style":"icas","q":"Solve: x³=−27","options":["x=−3","x=3","x=−9","x=9"],"answer":0,"exp":"∛(−27)=−3. (−3)³=−27."},{"id":"icam280131","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"hard","style":"icas","q":"What is the binomial expansion of (1+x)³?","options":["1+3x+3x²+x³","1+x³","1+3x³","3+3x+x²+x³"],"answer":0,"exp":"(1+x)³=C(3,0)+C(3,1)x+C(3,2)x²+C(3,3)x³=1+3x+3x²+x³."},{"id":"icam280132","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"Which test determines if an infinite series converges?","options":["Sum test","Ratio test","Comparison test","All of the above can be used"],"answer":3,"exp":"Multiple convergence tests exist: ratio, root, comparison, integral, alternating series tests. They apply in different situations."},{"id":"icam280133","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"What is ∫(from 0 to π) sin(x) dx?","options":["0","1","2","π"],"answer":2,"exp":"[−cos(x)] from 0 to π = −cos(π)−(−cos(0))=1+1=2."},{"id":"icam280134","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"medium","style":"icas","q":"What is the trace of matrix [[2,3],[4,5]]?","options":["7","8","10","15"],"answer":0,"exp":"Trace=sum of diagonal elements=2+5=7."},{"id":"icam280135","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is the cross product direction of i×j?","options":["i","j","k","0"],"answer":2,"exp":"i×j=k (right-hand rule). i,j,k are unit vectors in x,y,z directions."},{"id":"icam280136","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"medium","style":"icas","q":"d/dx(tan x)=?","options":["sec²x","cot x","−csc²x","cos²x"],"answer":0,"exp":"d/dx(tan x)=sec²x. Derived from sin/cos using quotient rule."},{"id":"icam280137","state":"AU","section":"icas_maths","grade":8,"topic":"Probability","difficulty":"hard","style":"icas","q":"What is Bayes' Theorem?","options":["P(A|B)=P(B|A)×P(A)/P(B)","P(A∩B)=P(A)+P(B)","P(A|B)=P(A)×P(B)","P(A∪B)=P(A|B)×P(B)"],"answer":0,"exp":"Bayes' Theorem: P(A|B)=P(B|A)P(A)/P(B). Updates probability of A given new evidence B."},{"id":"icam280138","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"What is the formula for the dot product of vectors a and b?","options":["a×b=|a||b|sinθ","a·b=|a||b|cosθ","a·b=|a||b|tanθ","a×b=|a||b|cosθ"],"answer":1,"exp":"Dot product: a·b=|a||b|cosθ (scalar). Cross product: a×b=|a||b|sinθ (vector)."},{"id":"icam280139","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"medium","style":"icas","q":"What is the period of sin(2x)?","options":["2π","π","4π","π/2"],"answer":1,"exp":"Period of sin(bx)=2π/b=2π/2=π."},{"id":"icam280140","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"hard","style":"icas","q":"For continuous compound interest, A=Pe^(rt). If P=1000, r=0.05, t=10, what is A?","options":["$1,628.89","$1,648.72","$1,500","$2,000"],"answer":1,"exp":"A=1000×e^(0.5)=1000×1.6487=1648.72."},{"id":"icam3x0001","state":"AU","section":"icas_maths","grade":2,"topic":"Addition","difficulty":"easy","style":"icas","q":"What is 23+45?","options":["58","67","68","78"],"answer":2,"exp":"23+45=68."},{"id":"icam3x0002","state":"AU","section":"icas_maths","grade":2,"topic":"Multiplication","difficulty":"easy","style":"icas","q":"4 rows of 6 chairs. Total?","options":["20","22","24","28"],"answer":2,"exp":"4×6=24."},{"id":"icam3x0003","state":"AU","section":"icas_maths","grade":2,"topic":"Fractions","difficulty":"easy","style":"icas","q":"1/2 of 36?","options":["14","16","18","20"],"answer":2,"exp":"36÷2=18."},{"id":"icam3x0004","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"hard","style":"icas","q":"Which is greatest: 3/4, 2/3, 5/8, 7/10?","options":["3/4","2/3","5/8","7/10"],"answer":0,"exp":"0.75>0.7>0.667>0.625. Answer: 3/4."},{"id":"icam3x0005","state":"AU","section":"icas_maths","grade":3,"topic":"Division","difficulty":"medium","style":"icas","q":"2.4kg of flour, bags of 400g. Bags needed?","options":["5","6","7","8"],"answer":1,"exp":"2400÷400=6 bags."},{"id":"icam3x0006","state":"AU","section":"icas_maths","grade":3,"topic":"Number","difficulty":"easy","style":"icas","q":"3²+4²=?","options":["20","25","30","35"],"answer":1,"exp":"9+16=25."},{"id":"icam3x0007","state":"AU","section":"icas_maths","grade":3,"topic":"Fractions","difficulty":"medium","style":"icas","q":"Class of 32, 3/8 play sport. How many?","options":["10","11","12","13"],"answer":2,"exp":"3/8×32=12."},{"id":"icam3x0008","state":"AU","section":"icas_maths","grade":4,"topic":"Geometry","difficulty":"easy","style":"icas","q":"Perimeter of rectangle 15m×9m?","options":["38m","40m","44m","48m"],"answer":3,"exp":"2(15+9)=48m."},{"id":"icam3x0009","state":"AU","section":"icas_maths","grade":4,"topic":"Percentage","difficulty":"medium","style":"icas","q":"60% of 150?","options":["80","85","90","95"],"answer":2,"exp":"0.6×150=90."},{"id":"icam3x0010","state":"AU","section":"icas_maths","grade":4,"topic":"Algebra","difficulty":"medium","style":"icas","q":"4x+3=27. x=?","options":["5","6","7","8"],"answer":1,"exp":"4x=24→x=6."},{"id":"icam3x0011","state":"AU","section":"icas_maths","grade":5,"topic":"Rates","difficulty":"medium","style":"icas","q":"7 workers build shed in 4 days. 14 workers?","options":["1","2","3","4"],"answer":1,"exp":"Double workers → half time. 2 days."},{"id":"icam3x0012","state":"AU","section":"icas_maths","grade":5,"topic":"Number","difficulty":"medium","style":"icas","q":"2⁸=?","options":["128","192","256","512"],"answer":2,"exp":"2^8=256."},{"id":"icam3x0013","state":"AU","section":"icas_maths","grade":5,"topic":"Statistics","difficulty":"hard","style":"icas","q":"Mean of 7 is 12; mean of 5 is 10. Mean of other 2?","options":["15","16","17","18"],"answer":2,"exp":"Total=84. 5×10=50. Sum of 2=34. Mean=17."},{"id":"icam3x0014","state":"AU","section":"icas_maths","grade":5,"topic":"Algebra","difficulty":"easy","style":"icas","q":"(x+y)² when x=3,y=4?","options":["37","47","49","51"],"answer":2,"exp":"7²=49."},{"id":"icam3x0015","state":"AU","section":"icas_maths","grade":5,"topic":"Rates","difficulty":"medium","style":"icas","q":"450km on 50L. How far on 35L?","options":["280km","290km","300km","315km"],"answer":3,"exp":"9km/L×35=315km."},{"id":"icam3x0016","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"hard","style":"icas","q":"Gradient of 3x+4y=24?","options":["−3/4","3/4","4/3","−4/3"],"answer":0,"exp":"y=−3x/4+6. m=−3/4."},{"id":"icam3x0017","state":"AU","section":"icas_maths","grade":6,"topic":"Algebra","difficulty":"easy","style":"icas","q":"Roots of x²−9=0?","options":["±3","±9","3 and 0","9 and 0"],"answer":0,"exp":"x=±3."},{"id":"icam3x0018","state":"AU","section":"icas_maths","grade":6,"topic":"Combinatorics","difficulty":"medium","style":"icas","q":"C(7,2)?","options":["14","21","28","35"],"answer":1,"exp":"7×6/2=21."},{"id":"icam3x0019","state":"AU","section":"icas_maths","grade":6,"topic":"Probability","difficulty":"hard","style":"icas","q":"P(sum≥10 on two dice)?","options":["1/6","1/9","1/12","1/4"],"answer":0,"exp":"6 outcomes out of 36=1/6."},{"id":"icam3x0020","state":"AU","section":"icas_maths","grade":7,"topic":"Geometry","difficulty":"hard","style":"icas","q":"Sphere volume=36π cm³. Radius?","options":["2cm","3cm","4cm","5cm"],"answer":1,"exp":"r³=27→r=3cm."},{"id":"icam3x0021","state":"AU","section":"icas_maths","grade":7,"topic":"Calculus","difficulty":"hard","style":"icas","q":"lim(x→∞)(3x+1)/(5x-2)?","options":["0","1/2","3/5","1"],"answer":2,"exp":"Divide by x: 3/5."},{"id":"icam3x0022","state":"AU","section":"icas_maths","grade":8,"topic":"Algebra","difficulty":"hard","style":"icas","q":"e^(2x)=7. Solve for x.","options":["ln7/2","2ln7","ln7","log7/2"],"answer":0,"exp":"x=ln7/2."},{"id":"icam3x0023","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"d/dx(x sinx)?","options":["cosx","sinx+xcosx","xcosx","sinx-xcosx"],"answer":1,"exp":"Product rule: sinx+xcosx."},{"id":"icam3x0024","state":"AU","section":"icas_maths","grade":8,"topic":"Calculus","difficulty":"hard","style":"icas","q":"∫(1 to e)(1/x)dx?","options":["0","1","e","1/e"],"answer":1,"exp":"[lnx] from 1 to e=1."},{"id":"icam3x0025","state":"AU","section":"icas_maths","grade":8,"topic":"Linear Algebra","difficulty":"hard","style":"icas","q":"Is AB always equal to BA for 2×2 matrices?","options":["Yes always","No — matrix multiplication is not generally commutative","Yes if square","Only for diagonal"],"answer":1,"exp":"AB≠BA in general."}];